import os
import numpy as np
import pandas as pd
import tensorflow as tf
from flask import Flask, request, jsonify, send_file
from werkzeug.utils import secure_filename
from werkzeug.exceptions import BadRequest
from sklearn.model_selection import train_test_split
from sklearn.preprocessing import LabelEncoder
from PIL import Image
import hashlib
import json
from datetime import datetime
import logging

app = Flask(__name__)
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024  # 16MB max file size
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['MODEL_FOLDER'] = 'models'
app.config['TRAINING_DATA_FOLDER'] = 'training_data'

# Create directories
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)
os.makedirs(app.config['MODEL_FOLDER'], exist_ok=True)
os.makedirs(app.config['TRAINING_DATA_FOLDER'], exist_ok=True)

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Security configuration
ALLOWED_EXTENSIONS = {'csv', 'jpg', 'jpeg', 'png'}
ALLOWED_IMAGE_EXTENSIONS = {'jpg', 'jpeg', 'png'}
MAX_FILE_SIZE = 16 * 1024 * 1024  # 16MB

# Global variables for model
model = None
label_encoder = None
model_path = os.path.join(app.config['MODEL_FOLDER'], 'community_model.h5')
training_data_path = os.path.join(app.config['TRAINING_DATA_FOLDER'], 'training_data.csv')

def allowed_file(filename, allowed_extensions):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in allowed_extensions

def validate_file(file, allowed_extensions):
    if not file:
        raise BadRequest("No file provided")
    
    if not allowed_file(file.filename, allowed_extensions):
        raise BadRequest("File type not allowed")
    
    if file.content_length > MAX_FILE_SIZE:
        raise BadRequest("File too large")

def create_model(num_classes):
    model = tf.keras.Sequential([
        tf.keras.layers.Conv2D(32, (3, 3), activation='relu', input_shape=(224, 224, 3)),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(128, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Flatten(),
        tf.keras.layers.Dense(512, activation='relu'),
        tf.keras.layers.Dropout(0.5),
        tf.keras.layers.Dense(num_classes, activation='softmax')
    ])
    
    model.compile(optimizer='adam',
                  loss='categorical_crossentropy',
                  metrics=['accuracy'])
    return model

def load_training_data():
    try:
        if os.path.exists(training_data_path):
            return pd.read_csv(training_data_path)
        return pd.DataFrame(columns=['filename', 'label'])
    except Exception as e:
        logger.error(f"Error loading training data: {e}")
        return pd.DataFrame(columns=['filename', 'label'])

def save_training_data(df):
    try:
        df.to_csv(training_data_path, index=False)
    except Exception as e:
        logger.error(f"Error saving training data: {e}")

def preprocess_image(image_path):
    try:
        image = Image.open(image_path)
        image = image.convert('RGB')
        image = image.resize((224, 224))
        image_array = np.array(image)
        image_array = image_array.astype('float32') / 255.0
        return image_array
    except Exception as e:
        logger.error(f"Error preprocessing image: {e}")
        return None

def train_model():
    global model, label_encoder
    
    try:
        df = load_training_data()
        if df.empty or len(df) < 2:
            logger.warning("Insufficient training data")
            return False
            
        # Encode labels
        label_encoder = LabelEncoder()
        df['label_encoded'] = label_encoder.fit_transform(df['label'])
        
        # Prepare data
        images = []
        labels = []
        
        for _, row in df.iterrows():
            image_path = os.path.join(app.config['UPLOAD_FOLDER'], row['filename'])
            if os.path.exists(image_path):
                image = preprocess_image(image_path)
                if image is not None:
                    images.append(image)
                    labels.append(row['label_encoded'])
        
        if not images:
            logger.warning("No valid images found")
            return False
            
        images = np.array(images)
        labels = tf.keras.utils.to_categorical(labels)
        
        # Split data
        X_train, X_test, y_train, y_test = train_test_split(
            images, labels, test_size=0.2, random_state=42, stratify=np.argmax(labels, axis=1)
        )
        
        # Create and train model
        num_classes = len(label_encoder.classes_)
        model = create_model(num_classes)
        
        # Train model
        model.fit(X_train, y_train,
                  epochs=10,
                  batch_size=32,
                  validation_data=(X_test, y_test),
                  verbose=0)
        
        # Save model
        model.save(model_path)
        logger.info("Model trained and saved successfully")
        return True
        
    except Exception as e:
        logger.error(f"Error training model: {e}")
        return False

@app.route('/upload', methods=['POST'])
def upload_file():
    try:
        if 'file' not in request.files:
            raise BadRequest("No file part")
        
        file = request.files['file']
        validate_file(file, ALLOWED_EXTENSIONS)
        
        if file.filename == '':
            raise BadRequest("No selected file")
        
        filename = secure_filename(file.filename)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(file_path)
        
        # If CSV file, process it
        if filename.endswith('.csv'):
            df = pd.read_csv(file_path)
            if 'filename' in df.columns and 'label' in df.columns:
                existing_df = load_training_data()
                combined_df = pd.concat([existing_df, df], ignore_index=True)
                save_training_data(combined_df)
                train_model()
                return jsonify({"message": "CSV data uploaded and model retrained"})
            else:
                raise BadRequest("CSV must contain 'filename' and 'label' columns")
        
        # If image file, add to training data
        elif filename.split('.')[-1].lower() in ALLOWED_IMAGE_EXTENSIONS:
            label = request.form.get('label', 'unknown')
            existing_df = load_training_data()
            new_row = pd.DataFrame({'filename': [filename], 'label': [label]})
            combined_df = pd.concat([existing_df, new_row], ignore_index=True)
            save_training_data(combined_df)
            train_model()
            return jsonify({"message": "Image uploaded and model retrained"})
        
        return jsonify({"message": "File uploaded successfully"})
        
    except BadRequest as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        logger.error(f"Upload error: {e}")
        return jsonify({"error": "Upload failed"}), 500

@app.route('/predict', methods=['POST'])
def predict():
    try:
        if 'file' not in request.files:
            raise BadRequest("No file part")
        
        file = request.files['file']
        validate_file(file, ALLOWED_IMAGE_EXTENSIONS)
        
        if file.filename == '':
            raise BadRequest("No selected file")
        
        filename = secure_filename(file.filename)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(file_path)
        
        if model is None:
            return jsonify({"error": "Model not trained yet"}), 400
        
        # Preprocess image
        image = preprocess_image(file_path)
        if image is None:
            return jsonify({"error": "Failed to process image"}), 400
        
        # Make prediction
        image = np.expand_dims(image, axis=0)
        predictions = model.predict(image)
        predicted_class = np.argmax(predictions[0])
        confidence = float(np.max(predictions[0]))
        
        # Decode label
        predicted_label = label_encoder.inverse_transform([predicted_class])[0]
        
        return jsonify({
            "prediction": predicted_label,
            "confidence": confidence,
            "all_predictions": {
                label_encoder.inverse_transform([i])[0]: float(predictions[0][i])
                for i in range(len(predictions[0]))
            }
        })
        
    except BadRequest as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        logger.error(f"Prediction error: {e}")
        return jsonify({"error": "Prediction failed"}), 500

@app.route('/model', methods=['GET'])
def get_model():
    try:
        if os.path.exists(model_path):
            return send_file(model_path, as_attachment=True)
        return jsonify({"error": "Model not found"}), 404
    except Exception as e:
        logger.error(f"Model download error: {e}")
        return jsonify({"error": "Failed to download model"}), 500

@app.route('/status', methods=['GET'])
def status():
    try:
        df = load_training_data()
        model_exists = os.path.exists(model_path)
        return jsonify({
            "model_trained": model_exists,
            "training_examples": len(df),
            "labels": list(label_encoder.classes_) if label_encoder is not None else [],
            "timestamp": datetime.now().isoformat()
        })
    except Exception as e:
        logger.error(f"Status error: {e}")
        return jsonify({"error": "Failed to get status"}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)